module KoggeStoneAdder (  
    input [4:0] A,  
    input [4:0] B,  
    output [4:0] SUM,  
    output COUT  
);  
    wire [4:0] G; // Generate  
    wire [4:0] P; // Propagate  
    wire [4:0] obf_C; // Carry  

    // Generate and Propagate  
    assign G = A & B;  
    assign P = A ^ B;  

    // Carry calculation  
    assign obf_C[0] = 1'b0;  
    assign obf_C[1] = G[0] | (P[0] & obf_C[0]);  
    assign obf_C[2] = G[1] | (P[1] & obf_C[1]);  
    assign obf_C[3] = G[2] | (P[2] & obf_C[2]);  
    assign obf_C[4] = G[3] | (P[3] & obf_C[3]);  

    // Sum calculation  
    assign SUM = P ^ obf_C[4:0];  
    assign COUT = G[4] | (P[4] & obf_C[4]);  
endmodule
